module counter_8bit_up_down(
    input clk, rst, dir,
    output reg [7:0] q);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            q <= 8'b00000000;
        else if (dir)
            q <= q + 1;
        else
            q <= q - 1;
    end
endmodule
